import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

// ── Helpers ─────────────────────────────────────────────────────────────────

/** Click a view mode option in the SegmentedControl (renders as input + label). */
async function switchView(page: import('@playwright/test').Page, mode: string) {
  await page.locator(`input[value="${mode}"] + label`).click()
}

/** Navigate to search and wait for results to load. */
async function searchAndWait(page: import('@playwright/test').Page) {
  await searchWith(page, {})
  await waitForResults(page)
}

// ── Critical tier ───────────────────────────────────────────────────────────

test.describe('Result views and detail modal', () => {
  test('card view renders institution cards with name, city, state @critical @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Default view is card — cards are rendered as Mantine Card elements with role="button"
    const cards = page.locator('[class*="mantine-Card-root"][role="button"]')
    await expect(cards.first()).toBeVisible({ timeout: 10_000 })

    const count = await cards.count()
    expect(count).toBeGreaterThan(0)

    // First card should contain institution name (bold text) and city, state
    const firstCard = cards.first()
    const nameText = firstCard.locator('p').first()
    await expect(nameText).not.toBeEmpty()

    // The second <p> holds "city, state" — verify it contains a comma
    const locationText = firstCard.locator('p').nth(1)
    await expect(locationText).toContainText(',')
  })

  test('click institution card opens detail modal with institution name and key metrics @critical @detail', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Click the first card to open the detail modal
    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    const institutionName = await firstCard.locator('p').first().textContent()
    expect(institutionName).toBeTruthy()

    await firstCard.click()

    // The modal should open with aria-label "Institution details"
    const modal = page.locator('[role="dialog"][aria-label="Institution details"]')
    await expect(modal).toBeVisible({ timeout: 10_000 })

    // Modal title should contain the institution name
    await expect(modal).toContainText(institutionName!)

    // Key metric sections should be visible: Academics, Cost, Outcomes
    await expect(modal.getByText('Academics')).toBeVisible()
    await expect(modal.getByText('Cost')).toBeVisible()
    await expect(modal.getByText('Outcomes')).toBeVisible()
  })

  // ── Standard tier ───────────────────────────────────────────────────────

  test('switch to list view renders list items with institution data @standard @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    await switchView(page, 'list')

    // List view renders Box elements with role="button" inside a Stack
    // Each item has institution name (bold, brand color) and "city, state"
    const listItems = page.locator(
      '[class*="mantine-Stack-root"] > [role="button"]',
    )
    await expect(listItems.first()).toBeVisible({ timeout: 10_000 })

    const count = await listItems.count()
    expect(count).toBeGreaterThan(0)

    // Each list item should contain a comma-separated location
    const firstItem = listItems.first()
    await expect(firstItem).toContainText(',')
  })

  test('switch to table view renders table with column headers @standard @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    await switchView(page, 'table')

    const table = page.locator('table')
    await expect(table).toBeVisible({ timeout: 10_000 })

    // The table should have a "Name" column header
    await expect(table.locator('th').filter({ hasText: 'Name' })).toBeVisible()

    // Should have data rows
    const rows = table.locator('tbody tr')
    await expect(rows.first()).toBeVisible()
    const rowCount = await rows.count()
    expect(rowCount).toBeGreaterThan(0)
  })

  test('switch to map view renders map container @standard @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    await switchView(page, 'map')

    // Leaflet map container has class "leaflet-container"
    const mapContainer = page.locator('.leaflet-container')
    await expect(mapContainer).toBeVisible({ timeout: 10_000 })

    // Map should contain tile layer images
    await expect(mapContainer.locator('.leaflet-tile-pane')).toBeVisible()
  })

  test('close detail modal returns to results, results still visible @standard @detail', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Open the detail modal
    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    await firstCard.click()

    const modal = page.locator('[role="dialog"][aria-label="Institution details"]')
    await expect(modal).toBeVisible({ timeout: 10_000 })

    // Close the modal via the close button
    await modal.locator('button[aria-label="Close"]').click()
    await expect(modal).toBeHidden()

    // Results should still be visible
    await expect(
      page.getByText(/institutions found|results/i),
    ).toBeVisible()

    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  // ── Comprehensive tier ────────────────────────────────────────────────────

  test('view preference persists across page reload via localStorage @comprehensive @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Switch to table view — this should persist to localStorage
    await switchView(page, 'table')
    await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })

    // Verify localStorage was set
    const storedView = await page.evaluate(() =>
      localStorage.getItem('kapow:results-view'),
    )
    expect(storedView).toBe('table')

    // Reload the page (without view= in URL to test localStorage fallback)
    await page.goto('/search')
    await waitForResults(page)

    // Table view should still be active after reload
    await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })
  })

  test('detail modal shows enrollment, tuition, graduation rate fields @comprehensive @detail', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Open the detail modal
    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    await firstCard.click()

    const modal = page.locator('[role="dialog"][aria-label="Institution details"]')
    await expect(modal).toBeVisible({ timeout: 10_000 })

    // Wait for institution data to load (loader disappears)
    await expect(modal.locator('[class*="mantine-Loader"]')).toBeHidden({
      timeout: 10_000,
    })

    // Verify key detail rows are present
    await expect(modal.getByText('Enrollment')).toBeVisible()
    await expect(modal.getByText('In-State Tuition')).toBeVisible()
    await expect(modal.getByText('Out-of-State Tuition')).toBeVisible()
    await expect(modal.getByText('Graduation Rate')).toBeVisible()
    await expect(modal.getByText('Admission Rate')).toBeVisible()
    await expect(modal.getByText('Retention Rate')).toBeVisible()
  })

  test('similar institutions section loads within detail modal @comprehensive @detail', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Open the detail modal
    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    await firstCard.click()

    const modal = page.locator('[role="dialog"][aria-label="Institution details"]')
    await expect(modal).toBeVisible({ timeout: 10_000 })

    // Wait for detail data to load
    await expect(modal.locator('[class*="mantine-Loader"]')).toBeHidden({
      timeout: 10_000,
    })

    // Click the "Find Similar Schools" button
    const similarButton = modal.getByRole('button', {
      name: 'Find Similar Schools',
    })
    await expect(similarButton).toBeVisible()
    await similarButton.click()

    // The "Similar Schools" heading should appear
    await expect(modal.getByText('Similar Schools')).toBeVisible({
      timeout: 10_000,
    })

    // Similar institution cards or a "no similar" message should be visible
    const similarCards = modal.locator(
      '[class*="mantine-Card-root"]:not([role="button"])',
    )
    const noSimilarMsg = modal.getByText('No similar institutions found.')

    // One of these should be visible
    await expect(
      similarCards.first().or(noSimilarMsg),
    ).toBeVisible({ timeout: 15_000 })
  })
})
